import { useEffect, useState } from "react";
import axios from "../api/axios";
import { useNavigate } from "react-router-dom";
import { useNotification } from "../context/NotificationContext";

export default function ParkingList() {
  const [lots, setLots] = useState([]);
  const [selectedDistrict, setSelectedDistrict] = useState("Tiruchirappalli");
  const navigate = useNavigate();
  const { showNotification } = useNotification();

  const tamilNaduDistricts = [
    "Ariyalur", "Chengalpattu", "Chennai", "Coimbatore", "Cuddalore",
    "Dharmapuri", "Dindigul", "Erode", "Kallakurichi", "Kanchipuram",
    "Kanniyakumari", "Karur", "Krishnagiri", "Madurai", "Mayiladuthurai",
    "Nagapattinam", "Namakkal", "Nilgiris", "Perambalur", "Pudukkottai",
    "Ramanathapuram", "Ranipet", "Salem", "Sivagangai", "Tenkasi",
    "Thanjavur", "Theni", "Thoothukudi", "Tiruchirappalli", "Tirunelveli",
    "Tirupathur", "Tiruppur", "Tiruvallur", "Tiruvannamalai", "Tiruvarur",
    "Vellore", "Viluppuram", "Virudhunagar"
  ];

  useEffect(() => {
    console.log("Fetching parking lots...");
    axios.get("/parking")
      .then(res => {
        console.log("Got lots:", res.data);
        setLots(res.data);
      })
      .catch(err => {
        console.error("Error fetching lots:", err);
        showNotification("error", "Failed to fetch parking lots. Check console/backend.");
      });
  }, []);

  return (
    <div style={{ animation: "fadeIn 0.5s ease-out" }}>
      <div style={{ marginBottom: "32px", textAlign: "center", display: "flex", flexDirection: "column", alignItems: "center" }}>
        <h2 style={{ fontSize: "2.5rem", color: "var(--text-primary)", marginBottom: "8px", fontWeight: "800", display: "flex", alignItems: "center", gap: "10px" }}>
           <i className="fa-solid fa-map-location-dot" style={{ color: "var(--accent-primary)" }}></i> Select Location
        </h2>
        
        <div style={{ marginTop: "24px", display: "flex", alignItems: "center", gap: "16px", background: "var(--bg-secondary)", padding: "16px 24px", borderRadius: "var(--radius-md)", boxShadow: "var(--shadow-sm)", border: "1px solid var(--border-subtle)" }}>
            <label style={{ fontWeight: "700", color: "var(--text-secondary)" }}>Active District:</label>
            <select 
                value={selectedDistrict} 
                onChange={(e) => setSelectedDistrict(e.target.value)}
                style={{
                    padding: "12px 20px",
                    borderRadius: "8px",
                    border: "1px solid var(--border-subtle)",
                    fontSize: "1.05rem",
                    outline: "none",
                    minWidth: "250px",
                    background: "white",
                    cursor: "pointer",
                    fontWeight: "600",
                    color: "var(--text-primary)"
                }}
            >
                {tamilNaduDistricts.map(d => (
                    <option key={d} value={d}>{d}</option>
                ))}
            </select>
        </div>
      </div>

      {selectedDistrict !== "Tiruchirappalli" ? (
          <div style={{ textAlign: "center", padding: "60px 20px", background: "var(--bg-secondary)", borderRadius: "var(--radius-lg)", border: "1px dashed var(--border-subtle)", animation: "fadeIn 0.5s" }}>
              <i className="fa-solid fa-rocket fa-4x" style={{ color: "var(--accent-secondary)", marginBottom: "20px" }}></i>
              <h2 style={{ fontSize: "2rem", color: "var(--text-primary)", marginBottom: "12px" }}>Coming Soon to {selectedDistrict}!</h2>
              <p style={{ color: "var(--text-secondary)", fontSize: "1.1rem", maxWidth: "600px", margin: "0 auto" }}>
                  ParkSense is rapidly expanding across Tamil Nadu. Operations in {selectedDistrict} are currently being set up. 
                  Check back soon for available smart parking lots in this district.
              </p>
          </div>
      ) : (
        <div className="grid">
        {lots.length === 0 && (
          <div style={{ gridColumn: "1/-1", textAlign: "center", padding: "40px", background: "var(--bg-secondary)", borderRadius: "var(--radius-lg)", border: "var(--border-subtle)" }}>
            <i className="fa-solid fa-spinner fa-spin fa-2x" style={{ color: "var(--accent-primary)" }}></i>
            <p style={{ marginTop: "16px", color: "var(--text-secondary)", fontWeight: "500" }}>Loading parking availability...</p>
          </div>
        )}
        {lots.map(lot => (
          <div className="card" key={lot._id}>
            {/* Header / Badge Area */}
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "16px" }}>
              <div style={{ background: "var(--accent-primary)", color: "white", width: "48px", height: "48px", borderRadius: "12px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "1.5rem", boxShadow: "0 4px 10px rgba(37, 99, 235, 0.3)" }}>
                <i className="fa-solid fa-square-parking"></i>
              </div>
              <span style={{ background: "var(--status-success-bg)", color: "var(--status-success)", padding: "4px 10px", borderRadius: "20px", fontSize: "0.75rem", fontWeight: "700", textTransform: "uppercase", letterSpacing: "0.5px" }}>
                <i className="fa-solid fa-bolt" style={{ marginRight: "4px" }}></i> Fast Book
              </span>
            </div>

            <div style={{ flexGrow: 1 }}>
              <h3 style={{ fontSize: "1.4rem", margin: "0 0 8px 0" }}>{lot.name}</h3>
              <p style={{ display: "flex", alignItems: "center", gap: "8px", color: "var(--text-secondary)", fontSize: "0.95rem", margin: 0 }}>
                <i className="fa-solid fa-location-dot" style={{ color: "var(--accent-secondary)" }}></i> {lot.location}
              </p>
            </div>

            <div style={{ marginTop: "24px", paddingTop: "16px", borderTop: "var(--border-subtle)" }}>
               <button className="btn-primary" onClick={() => navigate(`/slots/${lot._id}`)}>
                 View Availability <i className="fa-solid fa-arrow-right"></i>
               </button>
            </div>
          </div>
        ))}
      </div>
      )}
    </div>
  );
}
